css:
/*
 * @name: 粉白哥特风格
 * @author: 比巴卜
 * @description: 白色与粉色结合的精致风格（整站、气泡、AI 配置、角色卡等）
 * @version: 1.3-modified
*/

/* --- 字体导入 --- */
@import url("https://fonts.googleapis.com/css2?family=Grenze+Gotisch:wght@400;700&display=swap");

/* === 一、全局控制（主色调调整为白+粉） === */
:root {
    --custom-font: "Grenze Gotisch", cursive;
    /* 背景与面板 */
    --main-bg-color: linear-gradient(180deg, rgba(255,255,255,0.99), rgba(255,249,251,0.99));
    --panel-bg-color: rgba(255, 250, 252, 0.86); /* 轻微玻璃感白粉 */
    /* 气泡可以是径向渐变，顶部更接近白色，底部有粉色 */
    --bubble-bg-color: radial-gradient(ellipse at 50% 12%,
        rgba(255,255,255,0.98) 0%,
        rgba(255,245,250,0.95) 30%,
        rgba(255,230,240,0.85) 100%);
    /* 主/浅粉 */
    --main-pink-color: #ff88cc;
    --light-pink-color: #ffd6ea;
    --border-color: rgba(255,136,204,0.28);
    /* 文本：深色以确保对比度与可读性 */
    --text-color: #2b2b2b;
    --muted-text-color: #6f5a63;
    --shadow-color: rgba(255,136,204,0.18); /* 柔和的粉色阴影 */
    --glow-color: rgba(255,200,230,0.28);
}

/* 全局背景图（保留原图但用浅色覆盖以统一调性） */
#bg_custom {
    background-image: url('https://files.catbox.moe/pk0fin.jpg');
    background-size: cover;
    background-position: center;
    background-attachment: fixed;
    /* 覆盖层使整体偏白粉而不显突兀 */
    background-color: rgba(255,250,252,0.6);
    background-blend-mode: lighten;
}

/* 定义全局字体与文字颜色 */
body {
    font-family: var(--custom-font), "Helvetica Neue", Arial, sans-serif;
    color: var(--text-color);
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

/* 全局弹出面板主色调（毛玻璃 + 粉边） */
.drawer-content, #table_drawer_content, .options-content,
#ai-config-panel, #ai-config-modal, .ai-config-panel,
.persona-panel, .persona-card, .role-card, .role-card-expanded, .persona-expanded {
    background-color: var(--panel-bg-color) !important;
    border: 1px solid var(--border-color) !important;
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border-radius: 12px;
    color: var(--text-color) !important;
    box-shadow: 0 4px 30px var(--glow-color);
}

/* 为特定侧边面板提高不透明度并转为浅白粉 */
#left-nav-panel, #right-nav-panel {
    background-color: rgba(255, 250, 252, 0.95) !important;
    border: 1px solid var(--border-color) !important;
}

/* ===== 二、顶栏（白粉玻璃） ===== */
#top-settings-holder {
    background: var(--main-bg-color);
    box-shadow: 0 4px 18px rgba(0,0,0,0.03);
    border: 1px solid var(--border-color);
    border-radius: 15px;
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
}
#top-bar {
    background-color: transparent !important;
    box-shadow: none !important;
    border: none !important;
    border-radius: 15px !important;
}

/* -- 图标替换（保留原图但优化为适配浅色背景） -- */
#top-settings-holder .drawer-icon::before {
    content: '' !important;
    visibility: hidden;
}
#top-settings-holder .drawer-icon {
    display: block;
    margin: 0 auto;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    transition: all 0.28s cubic-bezier(.2,.9,.3,1);
    width: 32px;
    height: 32px;
    opacity: 1 !important;
    filter: drop-shadow(0 2px 8px rgba(255,160,210,0.12));
}
.drawer-icon.fa-fw:hover {
    transform: scale(1.12);
}

/* 保持已有图标路径，但在浅色背景下视觉更柔和 */
#ai-config-button .drawer-icon { background-image: url('https://files.catbox.moe/nqdnau.png'); }
#sys-settings-button .drawer-icon { background-image: url('https://files.catbox.moe/b3vb85.png'); }
#advanced-formatting-button .drawer-icon { background-image: url('https://files.catbox.moe/nqdnau.png'); }
#WI-SP-button .drawer-icon { background-image: url('https://files.catbox.moe/b3vb85.png'); }
#user-settings-button .drawer-icon { background-image: url('https://files.catbox.moe/nqdnau.png'); }
#logo_block .drawer-icon { background-image: url('https://files.catbox.moe/b3vb85.png'); }
#extensions-settings-button .drawer-icon { background-image: url('https://files.catbox.moe/nqdnau.png'); }
#persona-management-button .drawer-icon { background-image: url('https://files.catbox.moe/b3vb85.png'); }
#rightNavHolder .drawer-icon { background-image: url('https://files.catbox.moe/nqdnau.png'); }

/* ===== 三、底栏（输入框、按钮） ===== */
#send_form {
    background-color: var(--panel-bg-color) !important;
    border-radius: 15px !important;
    border: 1px solid var(--border-color) !important;
    padding: 10px;
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    box-shadow: 0 6px 24px var(--glow-color);
}
#send_textarea {
    border-radius: 10px !important;
    background-color: transparent !important;
    border-color: transparent !important;
    font-size: 0.55em;
    color: var(--text-color);
}

/* 底栏图标占位与适配 */
#send_form [class*="fa-"]::before {
    content: '' !important;
    display: inline-block;
    width: 28px;
    height: 28px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    vertical-align: middle;
}
#options_button::before { background-image: url('https://files.catbox.moe/4xg3ie.png') !important; }
#extensionsMenuButton::before { background-image: url('https://files.catbox.moe/e5mqug.png') !important; }
#quick-reply-rocket-button i::before { background-image: url('https://files.catbox.moe/e5mqug.png') !important; }
#send_but::before { background-image: url('https://files.catbox.moe/zk5xix.png') !important; }
#mes_stop i::before { background-image: url('https://files.catbox.moe/vqirnb.png') !important; }

/* ===== 四、聊天区域（气泡改为白粉径向渐变） ===== */
#chat {
    background-color: transparent !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
}
.mes {
    /* 使用变量中定义的径向渐变，使顶部更接近白色、底部粉化 */
    background: var(--bubble-bg-color) !important;
    border: 1px solid var(--border-color) !important;
    border-radius: 15px;
    padding: 15px;
    margin: 10px 0;
    backdrop-filter: blur(6px);
    -webkit-backdrop-filter: blur(6px);
    box-shadow: 0 6px 24px var(--shadow-color);
    color: var(--text-color);
}

/* 头像样式：白底或粉边更适配浅色主题 */
.mes .avatar img {
    border: 2px solid rgba(255,255,255,0.85);
    box-shadow: 0 8px 30px rgba(255,170,200,0.12);
    border-radius: 6px;
}

/* ==== 新增：头像装饰框 ==== */
.mes .avatar {
    position: relative;
    display: inline-block;
}
.mes .avatar img {
    border: 2px solid var(--main-pink-color);
    box-shadow: 0 0 10px var(--shadow-color);
    border-radius: 50%;
    position: relative;
    z-index: 2;
}
.mes .avatar::after {
    content: '';
    position: absolute;
    top: -20px;
    left: -15px;
    width: calc(100% + 26px);
    height: calc(100% + 26px);
    background: url('https://files.catbox.moe/hle7eg.png') no-repeat center;
    background-size: contain;
    pointer-events: none;
    z-index: 3;
}

/* 消息文字 */
.mes_text {
    width: 100%;
    padding: 0px;
    color: var(--text-color);
    text-shadow: none;
    line-height: 1.52;
}
.name_text {
    color: var(--main-pink-color);
    font-weight: 700;
    letter-spacing: 0.2px;
}

/* 垂直布局保持 */
.mes {
    display: flex !important;
    flex-direction: column !important;
    gap: 10px;
}
.mes_block {
    display: flex;
    flex-direction: column;
    gap: 8px;
}
.mesAvatarWrapper {
    display: flex;
    align-items: center;
    gap: 10px;
}

/* 文本强调颜色调整 */
em {
    color: var(--light-pink-color);
    font-style: italic;
}
q {
    color: var(--light-pink-color);
}
strong {
    color: var(--main-pink-color);
    font-weight: bold;
}

/* ===== 五、滚动条+滑动条（浅粉渐变） ===== */
::-webkit-scrollbar {
    width: 8px;
    background-color: transparent;
}
::-webkit-scrollbar-track {
    background-color: transparent;
}
::-webkit-scrollbar-thumb {
    background-image: linear-gradient(to bottom, var(--main-pink-color), var(--light-pink-color));
    border-radius: 10px;
    border: 1px solid rgba(255,255,255,0.6);
}

input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    width: 100%;
    background: transparent;
    cursor: pointer;
}
input[type="range"]::-webkit-slider-runnable-track {
    width: 100%;
    height: 6px;
    background: linear-gradient(to right, var(--main-pink-color), var(--light-pink-color));
    border-radius: 3px;
    border: 1px solid rgba(255,255,255,0.65);
}
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    margin-top: -8px;
    height: 20px;
    width: 20px;
    background-image: url('https://files.catbox.moe/nqdnau.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-color: transparent;
    border: none;
    border-radius: 0;
    box-shadow: none;
    transition: transform 0.18s ease;
}
input[type="range"]:hover::-webkit-slider-thumb,
input[type="range"]:active::-webkit-slider-thumb {
    transform: scale(1.15);
}
input[type="range"]::-moz-range-track {
    height: 6px;
    background: linear-gradient(to right, var(--main-pink-color), var(--light-pink-color));
    border-radius: 3px;
    border: 1px solid rgba(255,255,255,0.65);
}
input[type="range"]::-moz-range-thumb {
    height: 20px;
    width: 20px;
    background-image: url('https://files.catbox.moe/nqdnau.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-color: transparent;
    border: none;
    border-radius: 0;
}

/* ===== 六、输入框提示文字自定义（保留原提示但配色调整） ===== */
#nonQRFormItems {
    position: relative;
}
#send_textarea::placeholder {
    color: transparent !important;
    text-shadow: none !important;
}
#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
    content: "What secrets will you share?...";
    color: var(--main-pink-color);
    left: 50%;
    position: absolute;
    top: 50%;
    transform: translate(-50%, -50%);
    font-style: italic;
    font-size: 0.88em;
    pointer-events: none;
    z-index: 10;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: calc(100% - 180px);
}

/* ===== 七、正则+脚本易读+防误触（转为浅粉） ===== */
.regex-script-label.flex-container, .script-item {
    background-color: rgba(255,245,248,0.75) !important;
    border-radius: 8px;
    padding: 8px;
    margin-bottom: 5px;
    border: 1px solid rgba(255,220,235,0.6);
}
.regex-script-label.flex-container .regex_script_name, .script-item .script-item-name {
    flex-basis: 100%;
    margin-bottom: 8px;
    white-space: normal;
    overflow: visible;
    text-overflow: clip;
    word-break: break-word;
    font-weight: 700;
    color: var(--main-pink-color);
}
.regex-script-label.flex-container > .flex-container.flexnowrap, .script-item .script-item-control {
    width: 100%;
    justify-content: flex-start;
}

/* === AI 配置展开页面关闭条目字体颜色 === */
.option.disabled,
.option[disabled],
.switch-label.disabled,
.ai-config-panel .disabled,
.ai-config-panel [disabled] {
    color: #b35c85 !important; /* 深粉/紫红，和背景有对比 */
    opacity: 0.85; /* 保持有点“关闭”的感觉，但清晰可见 */
    text-shadow: none !important;
}

/* ===== 八、加载更多消息美化（白粉按钮） ===== */
#show_more_messages {
    background-color: rgba(255, 240, 247, 0.8);
    color: var(--main-pink-color);
    padding: 10px 25px;
    margin: 20px auto;
    border: 1px solid var(--border-color);
    border-radius: 20px;
    font-weight: 700;
    cursor: pointer;
    transition: all 0.18s ease-in-out;
    font-size: 0 !important;
}
#show_more_messages::before {
    content: 'Dig up more memories...';
    font-size: 1rem;
    color: var(--main-pink-color);
}
#show_more_messages:hover {
    background-color: rgba(255, 200, 230, 0.92);
    color: white;
    transform: translateY(-2px);
    box-shadow: 0 8px 24px rgba(255,150,200,0.18);
}
#show_more_messages:hover::before { color: white; }

/* ===== 九、思维链美化（粉色条 + 柔和背景） ===== */
.mes_reasoning_summary {
    list-style: none;
    cursor: pointer;
}
.mes_reasoning_header {
    background: linear-gradient(45deg, rgba(255,240,247,0.7), rgba(255,230,240,0.6));
    border: 1px solid var(--border-color);
    border-radius: 8px;
    padding: 8px 15px;
    transition: all 0.16s ease-in-out;
}
.mes_reasoning_summary:hover .mes_reasoning_header {
    transform: scale(1.01);
    box-shadow: 0 6px 20px var(--shadow-color);
}
.mes_reasoning_header_title {
    font-size: 0 !important;
}
.mes_reasoning_header_title::before {
    content: 'A secret thought...';
    font-size: 14px;
    color: var(--main-pink-color);
    font-weight: 700;
}
.mes_reasoning_arrow {
    font-size: 0 !important;
}
.mes_reasoning_arrow::before {
    content: '◆';
    font-size: 12px;
    color: var(--main-pink-color);
    display: inline-block;
    transition: transform 0.24s ease;
}
details[open] .mes_reasoning_arrow::before { transform: rotate(90deg); }
.mes_reasoning {
    margin-top: 5px;
    padding: 15px;
    background-color: rgba(255, 248, 250, 0.85);
    border-left: 3px solid var(--main-pink-color);
    border-radius: 0 8px 8px 0;
    color: var(--muted-text-color);
    font-size: 13px;
    line-height: 1.6;
}

/* ===== 十、收藏栏左右滑动查看角色（粉色滚动条） ===== */
#HotSwapWrapper { overflow: hidden; }
.hotswap.avatars_inline {
    display: flex;
    flex-wrap: nowrap;
    overflow-x: auto;
    scrollbar-width: thin;
    scrollbar-color: var(--main-pink-color) var(--panel-bg-color);
}
.hotswap.avatars_inline::-webkit-scrollbar { display: block; height: 4px; }
.hotswap.avatars_inline::-webkit-scrollbar-track { background: transparent; }
.hotswap.avatars_inline::-webkit-scrollbar-thumb {
    background-color: var(--main-pink-color);
    border-radius: 2px;
    box-shadow: none;
}

/* ===== 兼容性与小细节优化 ===== */
/* 某些内部组件可能使用深色样式作为默认，特意覆盖以适配白粉主题 */
.card, .panel, .modal, .dialog, .popover {
    background-color: var(--panel-bg-color) !important;
    color: var(--text-color) !important;
    border: 1px solid var(--border-color) !important;
    box-shadow: 0 10px 30px rgba(255,180,210,0.08) !important;
}

/* 交互焦点态更柔和 */
button:focus, a:focus, input:focus, textarea:focus {
    outline: 3px solid rgba(255,200,230,0.35);
    outline-offset: 2px;
}

/* 保持原有的图标占位但在浅色背景下更可见 */
.icon, .fa {
    filter: none;
}

/* 小屏适配（保证气泡在窄屏下依旧有呼吸） */
@media (max-width: 720px) {
    .mes {
        padding: 12px;
        border-radius: 12px;
    }
    #send_form { padding: 8px; }
}

/* --- 设置页标签页按钮（白粉风格） --- */
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
    display: flex !important;
    align-items: center;
    justify-content: space-between !important;
    background-color: #fffafc !important; /* 柔和白色背景 */
    border: 2px solid #f5a9c7 !important; /* 粉色边框 */
    color: #d45b91 !important; /* 粉色文字 */
    text-shadow: none !important; /* 去掉黑色阴影，保持清新 */
    width: calc(100% - 12px) !important;
    margin: 8px auto !important;
    padding: 0.7em 15px 0.7em 25px !important;
    border-radius: 12px !important;
    box-sizing: border-box;
    box-shadow: 0 3px 8px rgba(245, 169, 199, 0.25); /* 粉色柔和阴影 */
    font-weight: 600;
}

/* 去掉默认前缀图标 */
.inline-drawer-header::before,
#extensions_settings .inline-drawer-toggle.inline-drawer-header::before,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header::before,
#user-settings-block h4::before,
.standoutHeader::before {
    content: "" !important;
    display: none !important;
}

/* 箭头样式 */
.inline-drawer-header:not(.inline-drawer-toggle)::after { 
    display: none !important; 
}
.inline-drawer-toggle.inline-drawer-header::after { 
    color: #f080a1 !important; /* 亮粉色箭头 */
}

/* ===== 结束 ===== */
